use std::fs::OpenOptions;
use std::io::{self, Write};
use std::process::{Child, Command, Stdio};

fn main() {
    let freq = std::env::args()
        .nth(1)
        .unwrap_or_else(|| "152480000".to_string());

    if !command_exists("rtl_fm") {
        log_gateway("rtl_fm not found; cannot demodulate pager audio");
        std::process::exit(1);
    }
    if !command_exists("multimon-ng") {
        log_gateway("multimon-ng not found; install it for POCSAG/FLEX plaintext decoding");
        std::process::exit(1);
    }
    if !std::path::Path::new("./target/release/pager-residue-collector").exists() {
        log_gateway("pager-residue-collector missing; run cargo build --release --bin pager-residue-collector");
        std::process::exit(1);
    }

    let mut decoders = vec![
        "-a".to_string(),
        "POCSAG512".to_string(),
        "-a".to_string(),
        "POCSAG1200".to_string(),
        "-a".to_string(),
        "POCSAG2400".to_string(),
    ];
    if multimon_supports_flex() {
        decoders.push("-a".to_string());
        decoders.push("FLEX".to_string());
    }

    log_gateway(&format!(
        "Starting native pager resolver on {} Hz with {}",
        freq,
        decoders.join(" ")
    ));

    if let Err(err) = run_pipeline(&freq, &decoders) {
        log_gateway(&format!("pager resolver failed: {}", err));
        std::process::exit(1);
    }
}

fn run_pipeline(freq: &str, decoders: &[String]) -> io::Result<()> {
    let bridge_log = OpenOptions::new()
        .append(true)
        .create(true)
        .open("sdr_bridge.log")?;

    let mut rtl_fm = Command::new("rtl_fm")
        .args([
            "-f", freq, "-M", "fm", "-s", "22050", "-g", "auto", "-l", "0", "-",
        ])
        .stdout(Stdio::piped())
        .stderr(Stdio::from(bridge_log.try_clone()?))
        .spawn()?;

    let rtl_stdout = rtl_fm
        .stdout
        .take()
        .ok_or_else(|| io::Error::new(io::ErrorKind::BrokenPipe, "missing rtl_fm stdout"))?;

    let mut multimon_args = vec!["-t".to_string(), "raw".to_string()];
    multimon_args.extend(decoders.iter().cloned());
    multimon_args.push("-".to_string());

    let mut multimon = Command::new("multimon-ng")
        .args(&multimon_args)
        .stdin(Stdio::from(rtl_stdout))
        .stdout(Stdio::piped())
        .stderr(Stdio::from(bridge_log.try_clone()?))
        .spawn()?;

    let multimon_stdout = multimon
        .stdout
        .take()
        .ok_or_else(|| io::Error::new(io::ErrorKind::BrokenPipe, "missing multimon-ng stdout"))?;

    let mut collector = Command::new("./target/release/pager-residue-collector")
        .stdin(Stdio::from(multimon_stdout))
        .stderr(Stdio::inherit())
        .spawn()?;

    wait_child(&mut collector, "pager-residue-collector")?;
    wait_child(&mut multimon, "multimon-ng")?;
    wait_child(&mut rtl_fm, "rtl_fm")
}

fn wait_child(child: &mut Child, name: &str) -> io::Result<()> {
    let status = child.wait()?;
    if status.success() {
        Ok(())
    } else {
        Err(io::Error::other(
            format!("{} exited with {}", name, status),
        ))
    }
}

fn command_exists(name: &str) -> bool {
    let Some(paths) = std::env::var_os("PATH") else {
        return false;
    };
    std::env::split_paths(&paths).any(|dir| {
        let path = dir.join(name);
        path.is_file()
    })
}

fn multimon_supports_flex() -> bool {
    Command::new("multimon-ng")
        .args(["-a", "help"])
        .output()
        .map(|out| {
            let mut text = String::from_utf8_lossy(&out.stdout).to_string();
            text.push_str(&String::from_utf8_lossy(&out.stderr));
            text.to_ascii_uppercase().contains("FLEX")
        })
        .unwrap_or(false)
}

fn log_gateway(message: &str) {
    let log_msg = format!("[PAGER] {}", message);
    let _ = OpenOptions::new()
        .append(true)
        .create(true)
        .open("gateway.log")
        .and_then(|mut f| writeln!(f, "{}", log_msg));
    eprintln!("{}", log_msg);
}
